import{_ as o,o as r,c as i,ag as a}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Power Factor Correction","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/power-factor-correction.md","filePath":"es/power-quality/power-factor-correction.md"}'),t={name:"es/power-quality/power-factor-correction.md"};function s(n,e,c,l,p,d){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="power-factor-correction" tabindex="-1">Power Factor Correction <a class="header-anchor" href="#power-factor-correction" aria-label="Permalink to &quot;Power Factor Correction&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Power factor correction is the process of improving the efficiency of power usage by reducing reactive power in an electrical system.</p><p>It is commonly achieved by adding equipment that compensates for the reactive component of current, allowing more effective use of available power.</p><p>Poor power factor leads to higher currents, increased losses, and reduced system capacity.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of power factor correction is to:</p><ul><li>Reduce unnecessary current flow in the system</li><li>Improve energy efficiency and reduce losses</li><li>Increase available capacity of transformers and conductors</li><li>Avoid penalties from utility providers</li><li>Improve voltage stability</li></ul><p>Correcting power factor optimizes overall system performance.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>In many industrial systems, loads such as motors and transformers draw both active power and reactive power.</p><p>Reactive power does not perform useful work but is required for operation.</p><p>This results in a power factor less than 1.</p><p>Power factor correction is typically achieved by:</p><ul><li>Installing capacitor banks that supply reactive power locally</li><li>Reducing the amount of reactive power drawn from the source</li></ul><p>By compensating reactive power:</p><ul><li>Total current in the system decreases</li><li>Voltage drops are reduced</li><li>System efficiency improves</li></ul><p>Automatic systems can switch capacitor stages on or off based on load conditions.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Power factor correction is used in:</p><ul><li>Industrial facilities with large motor loads</li><li>Systems with inductive equipment such as transformers and reactors</li><li>Plants with high energy consumption and utility penalties</li><li>Distribution systems requiring improved efficiency</li><li>Installations with fluctuating load conditions</li></ul><p>It is widely applied in both industrial and commercial environments.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Target power factor</strong><br> Typically close to unity but not necessarily equal to 1</p></li><li><p><strong>Load variability</strong><br> Changing loads require automatic or staged correction systems</p></li><li><p><strong>Harmonics interaction</strong><br> Capacitors can interact with harmonics and create resonance</p></li><li><p><strong>System location</strong><br> Correction can be applied centrally or near individual loads</p></li><li><p><strong>Overcorrection</strong><br> Excessive compensation can lead to leading power factor and voltage rise</p></li><li><p><strong>Equipment sizing</strong><br> Must match reactive power requirements without oversizing</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Capacitor banks are the most common solution for power factor correction</li><li>Automatic systems improve performance in variable load conditions</li><li>Harmonic analysis is important before installing capacitors</li><li>Poorly designed systems can create resonance and amplify distortion</li><li>Regular inspection ensures capacitors and switching devices operate correctly</li></ul>',26)])])}const h=o(t,[["render",s]]);export{m as __pageData,h as default};
